private void UpdateItemIcon(ListViewItem listViewItem, Item item)
{
    string imageKey = item.GetImageFileName();

    // Убедимся, что изображение загружено, интегрируя здесь логику загрузки
    if (!ImageList.Images.ContainsKey(imageKey))
    {
        string imagePath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "BuyMenu", "ItemsIco", imageKey + ".png");
