            }
        }
    }

    listViewItem.ImageKey = imageKey; // Обновляем ключ изображения
}
```

Теперь каждый раз, когда вызывается `UpdateItemIcon`, метод также проверяет, есть ли изображение в `ImageList`, и если его нет, загружает изображение прежде, чем обновлять `ImageKey` элемента `ListViewItem`.

