       private void UpdateEnchantmentComboBox(ComboBox enchantmentComboBox, int level, ListViewItem listViewItem = null)
       {
           // Clear the items in the enchantment ComboBox.
           enchantmentComboBox.Items.Clear();

           if (level >= 4)
           {
               // Populate the enchantment ComboBox with new items since level is greater than or equal to 4.
               for (int i = 0; i <= 4; i++)
               {
                   enchantmentComboBox.Items.Add(i.ToString());
               }
           }
           else
           {
               // Add a single item "0" since the level is less than 4.
               enchantmentComboBox.Items.Add("0");

               // If a ListViewItem is provided, reset its enchantment value to "0".
               if (listViewItem != null)
               {
                   listViewItem.SubItems[enchantmentColumnIndex].Text = "0";
               }
           }
           enchantmentComboBox.SelectedIndex = 0;

           // Enable or disable the enchantment ComboBox based on the level.
           enchantmentComboBox.Enabled = level >= 4;
           int newCharm = int.TryParse(enchantmentComboBox.SelectedItem.ToString(), out int charmValue) ? charmValue : 0;
           if (listViewItem?.Tag is Item selectedItem)
           {
               selectedItem.Charms = newCharm; // Обновляем чары в объекте Item
               UpdateItemIcon(listViewItem, selectedItem); // Обновляем иконку элемента в ListView
           }
       }

