using System;
using System.Collections.Generic;
using System.Drawing;
using System.IO;
using System.Linq;
using System.Net.NetworkInformation;
using System.Reflection.Emit;
using System.Text;
using System.Threading.Tasks;
using System.Windows.Forms;

namespace Albion_Helper
{
    public class ItemsProcessing
    {
        private ListView BrowserList;
        private ListView InventoryList;
        private ImageList ImageList;
        private ItemsList itemsList;
        private int levelColumnIndex = 3;
        private int enchantmentColumnIndex = 4;

        public ItemsProcessing(ListView browserList, ListView inventoryList, ImageList imageList)
        {
            BrowserList = browserList;
            InventoryList = inventoryList;
            ImageList = imageList;
            itemsList = new ItemsList();

            LoadImagesToImageList();
            PopulateBrowseList();
            InitializeListViewMouseHandlers();
        }

        // Блок загрузки изображений и наполнение списков
        public void LoadImagesToImageList()
        {
            foreach (var item in itemsList.GetItems())
            {
                // Получаем ImageFileName для текущего item
                string imageFileName = item.GetImageFileName();

                // Теперь интегрируем содержимое метода LoadImageToImageList сюда
                if (!ImageList.Images.ContainsKey(imageFileName))
                {
                    string imagePath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "BuyMenu", "ItemsIco", imageFileName + ".png");
                    if (File.Exists(imagePath))
                    {
                        using (var bmpTemp = new Bitmap(imagePath))
                        {
                            ImageList.Images.Add(imageFileName, new Bitmap(bmpTemp));
                        }
                    }
                }
            }
        }
        private void UpdateItemIcon(ListViewItem listViewItem, Item item)
        {
            // Предположим, что GetImageFileName теперь должен учитывать уровень (Level) и чары (Charms)
            // item.GetImageFileName() должен возвращать уникальный ключ в зависимости от уровня и зачарования.
            string imageKey = item.GetImageFileName();

            if (!ImageList.Images.ContainsKey(imageKey))
            {
                string imagePath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "BuyMenu", "ItemsIco", imageKey + ".png");
                if (File.Exists(imagePath))
                {
                    using (var bmpTemp = new Bitmap(imagePath))
                    {
                        ImageList.Images.Add(imageKey, new Bitmap(bmpTemp));
                    }
                }
            }

            listViewItem.ImageKey = imageKey; // Обновляем ключ изображения
        }


        public void PopulateBrowseList()
        {
            List<Item> items = GetSortedItems();
            BrowserList.Items.Clear();
            foreach (Item item in items)
            {

                ListViewItem listViewItem = CreateBrowserListViewItem(item);
                BrowserList.Items.Add(listViewItem);
            }
        }

        public ListViewItem CreateBrowserListViewItem(Item item)
        {
            ListViewItem listViewItem = new ListViewItem
            {
                ImageKey = item.GetImageFileName(),
                Tag = item
            };
            listViewItem.SubItems.Add(item.EnglishName);
            listViewItem.SubItems.Add(item.GetLocalizedCategory());
            return listViewItem;
        }
        public ListViewItem CreateInventoryListViewItem(Item item)
        {
            ListViewItem listViewItem = new ListViewItem();
            listViewItem.ImageKey = item.GetImageFileName();
            listViewItem.SubItems.Add(item.GetFullEnglishName());
            listViewItem.SubItems.Add("1");
            listViewItem.SubItems.Add(item.Level.ToString());
            listViewItem.SubItems.Add(item.Charms.ToString());
            listViewItem.SubItems.Add(item.GetLocalizedCategory());
            listViewItem.Tag = item;
            return listViewItem;
        }
        public List<Item> GetSortedItems()
        {
            return itemsList.GetItems().OrderBy(item => item.EnglishName).ToList();
        }
        // Блок распознования в какой колонке произведено нажатие
        public void InitializeListViewMouseHandlers()
        {
            BrowserList.MouseClick += (sender, e) => HandleMouseClick((ListView)sender, e);
            InventoryList.MouseClick += (sender, e) => HandleMouseClick((ListView)sender, e);
        }

        private void HandleMouseClick(ListView listView, MouseEventArgs e)
        {
            if (e.Button == MouseButtons.Left)
            {
                ListViewHitTestInfo hit = listView.HitTest(e.X, e.Y);
                if (hit.SubItem != null)
                {
                    if (listView == InventoryList)
                    {
                        DisplayComboBoxOrTextBox(hit);
                    }
                }
            }
        }

        // Отображение выбора уровня и зачарования
        private void DisplayComboBoxOrTextBox(ListViewHitTestInfo hit)
        {
            int yOffset = 65; // Смещение по вертикали
                              // Индексы столбцов (могут быть другими - настроить под свою структуру)
            int quantityColumnIndex = 2; // Индекс колонки для количества
            int levelColumnIndex = 3; // Индекс колонки для уровня
            int enchantmentColumnIndex = 4; // Индекс колонки для чаров

            // Проверяем, что клик был по интересующим нас колонкам в InventoryList
            int columnIndex = hit.Item.SubItems.IndexOf(hit.SubItem);
            if (columnIndex == quantityColumnIndex || columnIndex == levelColumnIndex || columnIndex == enchantmentColumnIndex)
            {
                // Определяем границы ячейки и контрол для отображения
                Rectangle cellBounds = hit.SubItem.Bounds;
                cellBounds.Offset(15, yOffset);
                cellBounds.Height -= yOffset; // Корректируем высоту с учетом смещения
                Control controlToDisplay = null;

                // Создание и настройка TextBox для количества
                if (columnIndex == quantityColumnIndex)
                {
                    TextBox quantityTextBox = new TextBox
                    {
                        Bounds = cellBounds,
                        Text = hit.SubItem.Text,
                        Tag = hit.Item
                    };
                    quantityTextBox.Leave += TextBox_Leave;
                    hit.Item.ListView.Parent.Controls.Add(quantityTextBox);
                    quantityTextBox.BringToFront();
                    quantityTextBox.Visible = true;
                    quantityTextBox.Focus();
                    quantityTextBox.Leave += (sender, e) => quantityTextBox.Visible = false;
                    quantityTextBox.KeyPress += (sender, e) =>
                    {
                        if (!char.IsControl(e.KeyChar) && !char.IsDigit(e.KeyChar))
                        {
                            e.Handled = true;
                        }
                    };
                    quantityTextBox.KeyDown += (sender, e) =>
                    {
                        if (e.KeyCode == Keys.Enter || e.KeyCode == Keys.Return)
                        {
                            hit.SubItem.Text = quantityTextBox.Text;
                            quantityTextBox.Visible = false;
                        }
                    };
                    controlToDisplay = quantityTextBox;
                }
                else
                {
                    ComboBox comboBox = new ComboBox
                    {
                        Bounds = cellBounds,
                        DropDownStyle = ComboBoxStyle.DropDownList,
                        Tag = hit.Item
                    };
                    comboBox.Name = columnIndex == levelColumnIndex ? "level" : "enchantment";
                    comboBox.Leave += (sender, e) => comboBox.Visible = false;
                    comboBox.SelectedIndexChanged += ComboBox_SelectedIndexChanged;
                    if (columnIndex == levelColumnIndex)
                    {
                        int minLevel = (hit.Item.Tag as Item)?.MinLevel ?? 1;
                        for (int i = minLevel; i <= 8; i++)
                        {
                            comboBox.Items.Add(i.ToString());
                        }
                        comboBox.SelectedItem = hit.SubItem.Text;
                        comboBox.SelectedIndexChanged += LevelComboBox_SelectedIndexChanged;
                    }
                    else if (columnIndex == enchantmentColumnIndex)
                    {
                        Item item = hit.Item.Tag as Item;
                        int currentLevel = Convert.ToInt32(hit.Item.SubItems[levelColumnIndex].Text);

                        if (currentLevel >= 4)
                        {
                            for (int i = 0; i <= 4; i++)
                            {
                                comboBox.Items.Add(i.ToString());
                            }
                        }
                        else
                        {
                            hit.Item.SubItems[enchantmentColumnIndex].Text = "0";
                            return;
                        }
                        comboBox.SelectedItem = hit.SubItem.Text;
                    }

                    controlToDisplay = comboBox;
                }
                if (controlToDisplay != null)
                {
                    hit.Item.ListView.Parent.Controls.Add(controlToDisplay);
                    controlToDisplay.BringToFront();
                    controlToDisplay.Visible = true;
                    controlToDisplay.Focus();
                }
            }
        }
        private void ComboBox_SelectedIndexChanged(object sender, EventArgs e)
        {
            // Убедимся, что sender - это ComboBox.
            ComboBox comboBox = sender as ComboBox;
            if (comboBox == null) return;

            // Получение связанного ListViewItem из Tag ComboBox’а.
            ListViewItem listViewItem = comboBox.Tag as ListViewItem;
            if (listViewItem == null) return;

            int subItemIndex = 0;
            if (comboBox.Name == "level")
            {
                subItemIndex = levelColumnIndex; // Назначаем индекс для колонки уровня

            }
            else if (comboBox.Name == "enchantment")
            {
                subItemIndex = enchantmentColumnIndex; // Назначаем индекс для колонки чар
            }

            if (comboBox.SelectedItem != null)
            {
