                {
                    Bounds = listViewItem.SubItems[enchantmentColumnIndex].Bounds,
                    DropDownStyle = ComboBoxStyle.DropDownList,
                    Tag = listViewItem,
                    Name = "enchantment"
                };
                enchantmentComboBox.SelectedIndexChanged += ComboBox_SelectedIndexChanged;
                listViewItem.ListView.Controls.Add(enchantmentComboBox);
