        ComboBox comboBox = sender as ComboBox;
        if (comboBox == null || comboBox.Tag == null) return;

        ListViewItem listViewItemToUpdate = comboBox.Tag as ListViewItem;
        if (listViewItemToUpdate == null) return;

        if (listViewItemToUpdate.Tag is Item itemToUpdate)
        {
            // Назначаем выбранное значение качества свойству Quality объекта Item
